import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"21. Fixed Term Employment","description":"","frontmatter":{"title":"21. Fixed Term Employment","eba":"Nurses and Midwives 2024-2028","topics":["employment"]},"headers":[],"relativePath":"ebas/nurses-midwives/employment-types/21-fixed-term-employment.md","filePath":"ebas/nurses-midwives/employment-types/21-fixed-term-employment.md"}'),i={name:"ebas/nurses-midwives/employment-types/21-fixed-term-employment.md"};function a(s,e,p,l,m,c){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_21-fixed-term-employment" tabindex="-1">21. Fixed Term Employment <a class="header-anchor" href="#_21-fixed-term-employment" aria-label="Permalink to &quot;21. Fixed Term Employment&quot;">​</a></h1><p><strong>21.1</strong> A fixed term Employee is an Employee who is employed:</p><p><strong>(a)</strong> for a specified period of time, which period is known at the commencement of the contract; or</p><p><strong>(b)</strong> for a specified task such as a project or replacement of an absent Employee; or</p><p><strong>(c)</strong> for a fixed period,</p><p>which in each case can be terminated earlier than the relevant expiration date in accordance with subclauses 21.6(c) or (d).</p><p><strong>21.2</strong> Subject to clause 21.4, fixed term employment will not be used to fill an ongoing position.</p><p><strong>21.3</strong> Limitations on the use of fixed term contracts</p><p><strong>(a)</strong> Subject to subclause 21.3(b), the following limitations apply to the use of fixed term contracts:</p><p><strong>(i)</strong> the fixed term contract will not be for an employment term of longer than 2 years, including any extensions or renewals;</p><p><strong>(ii)</strong> a fixed term contract will not include an option to extend or renew the Employee&#39;s employment more than once, or extend or renew such that employment period would be longer than 2 years; and</p><p><strong>(iii)</strong> the Employer will not offer an Employee a fixed term contract if it is to come into effect after another contract of employment if:</p><p><strong>(A)</strong> the previous contract included a term that provided the contract would terminate at the end of an identifiable period;</p><p><strong>(B)</strong> under the previous contract, the Employee was to perform the same, or substantially similar work to that which they are or would be required to work under the new contract; and</p><p><strong>(C)</strong> at least one of the following applies:</p><p>1) the previous contract contained an option to extend, and the contract was extended; or</p><p>2) the total employment period will now be more than 2 years; or</p><p>3) the new contract contains an option to renew or extend; or</p><p>4) the previous contract came into effect after another contract which specified termination at the end of an identifiable period, there was substantial continuity in the employment relationship during the period of the initial contract termination and the previous contract taking effect.</p><p><strong>(b)</strong> The limitations at 21.3(a) do not apply where:</p><p><strong>(i)</strong> the Employee is working on a specific task requiring specialised skills not usually available through Employees of the Employer; or</p><p><strong>(ii)</strong> the Employee&#39;s engagement is for the duration of a training arrangement; or</p><p><strong>(iii)</strong> the Employee is performing essential work during a peak demand period; or</p><p><strong>(iv)</strong> the Employee is working during emergency circumstances or replacing another Employee who is temporarily absent; or</p><p><strong>(v)</strong> the Employee&#39;s income is above the high-income threshold (which is provided for in the Act); or</p><p><strong>(vi)</strong> the Employee&#39;s position is partially or fully funded by government funding, which has been granted for a set period which is more than 2 years but is unlikely to be renewed;</p><p><strong>(vii)</strong> the contract relates to a governance position that has a relevant time limit;</p><p><strong>(viii)</strong> a modern award that covers the Employee otherwise allows for the use of a Fixed Term Contract; or</p><p><strong>(ix)</strong> the contract is of a kind prescribed by the FW Regulations.</p><p><strong>21.4</strong> Examples of where fixed term employment may be appropriate include:</p><p><strong>(a)</strong> RUSON/RUSOM positions;</p><p><strong>(b)</strong> Graduate Nurse/Midwife positions;</p><p><strong>(c)</strong> Post Graduate training positions;</p><p><strong>(d)</strong> Long term WorkCover replacement;</p><p><strong>(e)</strong> Special Projects;</p><p><strong>(f)</strong> Positions created through identifiable funding external to the Employer not being funding that is part of an operating grant from government; and</p><p><strong>(g)</strong> Backfill including for extended leave (such as Parental Leave and Long Service Leave) and to support flexible working arrangements.</p><p>Note: In this context, backfill to support flexible working arrangements does not refer to the Employee on the flexible working arrangement, but instead to an arrangement to work hours that arise from a flexible work arrangement that includes a temporary reduction in hours.</p><p><strong>21.5</strong> If an Employer and Employee enter into a fixed term contract which is not permitted under this Agreement, the term of the contract that provides that it will terminate at the end of an identifiable period is taken to have no effect, and the validity of the contract will otherwise not be affected.</p><p><strong>21.6</strong> General features of fixed term contracts</p><p><strong>(a)</strong> An Employee who continues working in the same role for the Employer following the expiry date of a fixed term contract, may, in accordance with the Act, be deemed a permanent Employee.</p><p><strong>(b)</strong> An Employer must specify the rationale for fixed term employment, in the Employee’s Letter of Appointment.</p><p><strong>(c)</strong> An Employee may terminate the fixed term employment by the giving of notice in accordance with subclause 23.1(e) of this Agreement. No notice is required when the contract has reached its expiry date.</p><p><strong>(d)</strong> An Employer may terminate a fixed term Employee in accordance with subclauses 15.5(a)(i)(E), 15.5(a)(ii)(A) or 23.1(f).</p><p><strong>21.7</strong> Disputes under this clause</p><p>All disputes raised under this clause 21 are to be dealt with in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a> (Dispute Resolution Procedure).</p><p><strong>21.8</strong> Graduates and Nurses/Midwives undertaking Post Graduate Studies</p><p>Graduates and Nurses/Midwives undertaking Post Graduate studies, who have successfully completed their program/course will be offered ongoing employment at the end of their fixed term contract where an appropriately classified vacancy exists.</p><p>Plain language terms: contract, fixed term.</p>',49)])])}const g=t(i,[["render",a]]);export{h as __pageData,g as default};
